#!/bin/bash\n# Build script for Ag-Lancher\n\nset -e\n\necho \"========================================\"\necho \"Ag-Lancher Build System\"\necho \"========================================\"\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\n# Configuration\nSOLUTION_FILE=\"Ag-Lancher.sln\"\nOUTPUT_DIR=\"./publish\"\n\necho -e \"${YELLOW}Restoring dependencies...${NC}\"\ndotnet restore\n\necho -e \"${YELLOW}Building solution...${NC}\"\ndotnet build -c Release\n\necho -e \"${YELLOW}Publishing Desktop (Windows)...${NC}\"\ndotnet publish src/Desktop/AgLauncher.Desktop.csproj -c Release -o \"$OUTPUT_DIR/Desktop/Windows\" -r win-x64 --self-contained\n\necho -e \"${YELLOW}Publishing Desktop (Linux)...${NC}\"\ndotnet publish src/Desktop/AgLauncher.Desktop.csproj -c Release -o \"$OUTPUT_DIR/Desktop/Linux\" -r linux-x64 --self-contained\n\necho -e \"${YELLOW}Publishing Desktop (macOS)...${NC}\"\ndotnet publish src/Desktop/AgLauncher.Desktop.csproj -c Release -o \"$OUTPUT_DIR/Desktop/macOS\" -r osx-x64 --self-contained\n\necho -e \"${YELLOW}Building Mobile (Android)...${NC}\"\ncd src/Mobile\ndotnet build -c Release -f net6.0-android\ncd ../..\n\necho -e \"${YELLOW}Building JAR...${NC}\"\nmkdir -p \"$OUTPUT_DIR/JAR\"\ncd src/JAR\njavac LauncherWrapper.java -d .\njar cvf \"../../$OUTPUT_DIR/JAR/AgLauncher.jar\" com/\ncd ../..\n\necho -e \"${GREEN}========================================${NC}\"\necho -e \"${GREEN}Build completed successfully!${NC}\"\necho -e \"${GREEN}Output directory: $OUTPUT_DIR${NC}\"\necho -e \"${GREEN}========================================${NC}\"\n\necho \"\"\necho \"Build artifacts:\"\necho \"  - Windows EXE: $OUTPUT_DIR/Desktop/Windows/AgLauncher.exe\"\necho \"  - Linux Binary: $OUTPUT_DIR/Desktop/Linux/AgLauncher\"\necho \"  - macOS App: $OUTPUT_DIR/Desktop/macOS/AgLauncher\"\necho \"  - Android APK: Build in src/Mobile/bin/Release\"\necho \"  - JAR: $OUTPUT_DIR/JAR/AgLauncher.jar\"\n